#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000
#define INF 1000000

int minDistance(int XGeneo, int YGeneo, int CNorth, int CSouth, int CEast, int CWest, int P) {
    int queue[MAX * MAX * 2], front = 0, rear = 0;
    int visited[MAX][MAX] = {0};
    int dx[] = {0, 0, 1, -1};
    int dy[] = {1, -1, 0, 0};
    int energy[] = {CNorth, CSouth, CEast, CWest};
    queue[rear++] = 0;
    queue[rear++] = 0;
    queue[rear++] = P;
    visited[0][0] = 1;
    while (front < rear) {
        int x = queue[front++];
        int y = queue[front++];
        int p = queue[front++];
        if (x == XGeneo && y == YGeneo && p == 0) return rear / 3 - 1;
        for (int i = 0; i < 4; i++) {
            int nx = x + dx[i];
            int ny = y + dy[i];
            int np = p - energy[i];
            if (np >= 0 && !visited[nx][ny]) {
                queue[rear++] = nx;
                queue[rear++] = ny;
                queue[rear++] = np;
                visited[nx][ny] = 1;
            }
        }
    }
    return -1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int XGeneo, YGeneo, CNorth, CSouth, CEast, CWest, P;
        scanf("%d %d %d %d %d %d %d", &XGeneo, &YGeneo, &CNorth, &CSouth, &CEast, &CWest, &P);
        printf("%d\n", minDistance(XGeneo, YGeneo, CNorth, CSouth, CEast, CWest, P));
    }
    return 0;
}

