int minDistance(int XGeneo, int YGeneo, int CNorth, int CSouth, int CEast, int CWest, int P) {
    queue<pair<pair<int, int>, int>> q;
    vector<vector<bool>> visited(MAX, vector<bool>(MAX, false));
    int dx[] = {0, 0, 1, -1};
    int dy[] = {1, -1, 0, 0};
    int energy[] = {CNorth, CSouth, CEast, CWest};
    q.push({{0, 0}, P});
    visited[0][0] = true;
    int distance = 0;
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; i++) {
            int x = q.front().first.first;
            int y = q.front().first.second;
            int p = q.front().second;
            q.pop();
            if (x == XGeneo && y == YGeneo && p == 0) return distance;
