        }
    }

    public static int minDistance(int XGeneo, int YGeneo, int CNorth, int CSouth, int CEast, int CWest, int P) {
        Queue<int[]> queue = new LinkedList<>();
        boolean[][] visited = new boolean[1000][1000];
        int[] dx = {0, 0, 1, -1};
        int[] dy = {1, -1, 0, 0};
        int[] energy = {CNorth, CSouth, CEast, CWest};
        queue.offer(new int[] {0, 0, P});
        visited[0][0] = true;
        int distance = 0;
        while (!queue.isEmpty()) {
            int size = queue.size();
            for (int i = 0; i < size; i++) {
                int[] current = queue.poll();
                int x = current[0];
                int y = current[1];
                int p = current[2];
                if (x == XGeneo && y == YGeneo && p == 0) return distance;
                for (int j = 0; j < 4; j++) {
                    int nx = x + dx[j];
                    int ny = y + dy[j];
                    int np = p - energy[j];
                    if (np >= 0 && !visited[nx][ny]) {
                        queue.offer(new int[] {nx, ny, np});
                        visited[nx][ny] = true;
                    }
                }
            }
            distance++;
        }
        return -1;
    }
