from collections import deque

def minDistance(XGeneo, YGeneo, CNorth, CSouth, CEast, CWest, P):
    queue = deque([(0, 0, P)])
    visited = {(0, 0): True}
    dx = [0, 0, 1, -1]
    dy = [1, -1, 0, 0]
    energy = [CNorth, CSouth, CEast, CWest]
    distance = 0
    while queue:
        for _ in range(len(queue)):
            x, y, p = queue.popleft()
            if x == XGeneo and y == YGeneo and p == 0:
                return distance
            for i in range(4):
                nx, ny, np = x + dx[i], y + dy[i], p - energy[i]
                if np >= 0 and (nx, ny) not in visited:
                    queue.append((nx, ny, np))
                    visited[(nx, ny)] = True
        distance += 1
    return -1

